let table = defaultContext.getData("table");

if({{table:purchase_order_no_type}} !== -9999 && (
  !{{table:purchase_order_no}} || {{table:purchase_order_no}} === null || {{table:purchase_order_no}} === ''
)) {
  table.purchase_order_no = 'draft'
}

return table;

return {
  required_fields: JSON.stringify([
  { name: "po_plant", label: "Plant" },
  { name: "purchase_order_no", label: "PO Number" },
  {
    name: "table_po",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    po_plant: {{table:po_plant}},
    purchase_order_no: {{table:purchase_order_no}},
    table_po: {{table:table_po}}
  })
}

let table = defaultContext.getData("table");

if (
  {{table:purchase_order_no_type}} !== -9999 &&
  (!{{table:purchase_order_no}} ||
    {{table:purchase_order_no}} === null ||
    {{table:purchase_order_no}} === "" ||
    {{table:previous_status}} !== "Issued")
) {
  table.purchase_order_no = 'issued'
}

return table;

return {
  required_fields: JSON.stringify([
  { name: "po_supplier_id", label: "Supplier Name" },
  { name: "po_plant", label: "Plant" },
  { name: "purchase_order_no", label: "PO Number" },
  {
    name: "table_po",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    po_supplier_id: {{table:po_supplier_id}},
    po_plant: {{table:po_plant}},
    purchase_order_no: {{table:purchase_order_no}},
    table_po: {{table:table_po}}
  })
}

let table = defaultContext.getData("table");

let table_po = {{table:table_po}}.filter(item => (item.item_id || item.item_desc || item.item_name) && item.quantity > 0)

defaultContext.setNestedData("table.table_po", table_po);
return table;

const draftGRCount = {{node:search_node_63QuSELy.data.total}};
const draftPICount = {{node:search_node_d32R9Uuk.data.total}};
let message = [];
let status = 'Passed';

if(draftGRCount > 0) {
  const draftGRNo = {{node:search_node_63QuSELy.data.data.gr_no}};
  message.push(draftGRNo);
}

if(draftPICount > 0) {
  const draftPINo = {{node:search_node_d32R9Uuk.data.data.purchase_invoice_no}};
  message.push(draftPINo);
}

if(message.length > 0) {
  status = 'Failed'
}

return {
  status: status,
  message: status === 'Passed' ? '' : 'The purchase order has existing GR/PI records in draft status. Proceeding will delete these record: ' + message.join(', ')
}

const poLineItem = {{table:table_po}};
const preqData = {{node:search_node_C8KBEzln.data.data}}
const onOrderData = {{node:search_node_chTs3Sss.data.data}}

if(preqData.length > 0) {
  for(const preq of preqData) {
    for(const preqItem of preq.table_pr) {
      const poItem = poLineItem.find(item => item.preq_line_id === preqItem.id);
      let orderQty = 0;

      if(poItem) {
        if(onOrderData.length > 0) {
          const onPOItem = onOrderData.find(item => item.parent_line_id === preqItem.id);
          orderQty = parseFloat(preqItem.order_qty) - parseFloat(onPOItem.scheduled_qty) + parseFloat(poItem.quantity)
        } else {
          orderQty = parseFloat(preqItem.order_qty) + parseFloat(poItem.quantity)
        }

        if((orderQty > parseFloat(preqItem.pr_line_qty)) && preq.preq_type === 'Contract') {
          return {
            status: "Failed",
            message: 'Total ordered qty exceed the limit.'
          }
        }
      } 
    }
  }
}

return {
  status: 'Passed',
  message: ''
}

let updatedLineItem = [];

for(const [index, poLineItem] of {{table:table_po}}.entries()) {
  // Create a new object with formatted values
  const formattedItem = {
    // Copy all existing properties
    ...poLineItem,

    // Apply number formatting to numeric fields
    quantity: parseFloat(poLineItem.quantity?.toFixed(3)) || 0,
    unit_price: parseFloat(poLineItem.unit_price?.toFixed(4)) || 0,
    gross: parseFloat(poLineItem.gross?.toFixed(4)) || 0,
    discount: parseFloat(poLineItem.discount?.toFixed(4)) || 0,
    discount_amount: parseFloat(poLineItem.discount_amount?.toFixed(4)) || 0,
    tax_amount: parseFloat(poLineItem.tax_amount?.toFixed(4)) || 0,
    po_amount: parseFloat(poLineItem.po_amount?.toFixed(4)) || 0,

    // Override with new field assignments
    supplier_id: {{table:po_supplier_id}} || null,
    plant_id: {{table:po_plant}} || null,
    payment_term_id: {{table:po_payment_terms}} || null,
    shipping_preference_id: {{table:po_shipping_preference}} || null,
    billing_state_id: {{table:billing_address_state}} || null,
    billing_country_id: {{table:billing_address_country}} || null,
    shipping_state_id: {{table:shipping_address_state}} || null,
    shipping_country_id: {{table:shipping_address_country}} || null,
    line_index: index + 1,
    organization_id: {{table:organization_id}},
    line_status: {{table:po_status}},
    po_created_by: {{global:nickname}}
  };

  updatedLineItem.push(formattedItem);
}

let table = defaultContext.getData("table");

if (
  (!{{table:partially_received}} || {{table:partially_received}} === "") &&
  (!{{table:fully_received}} || {{table:fully_received}} === "")
) {
  const lineItemLength = updatedLineItem.length;

  table.partially_received = `0 / ${lineItemLength}`;
  table.fully_received = `0 / ${lineItemLength}`;
}

defaultContext.setNestedData("table.table_po", updatedLineItem);
return table;

const lineItem = {{table:table_po}};

const uniqueItemIDs = [
  ...new Set(lineItem.filter((item) => item.item_id).map((item) => item.item_id))
];

return {
  itemIDs: uniqueItemIDs
}
